1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	interface Item {
5	  type: string;
6	  material?: string;
7	  enchantment?: number;
8	  cursed?: boolean;
9	}
10	
11	interface QuoteStep {
12	  op: "quote";
13	  items: Item[];
14	}
15	
16	interface Scenario {
17	  customer: { yearsWithMHPCO: number };
18	  steps: QuoteStep[];
19	}
20	
21	interface QuoteResult {
22	  premium: number;
23	}
24	
25	const COMPONENT_BASE_PREMIUM = 25;
26	
27	const BASE_PREMIUMS: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  rune: COMPONENT_BASE_PREMIUM,
33	  moonstone: COMPONENT_BASE_PREMIUM,
34	};
35	
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	const BLOCK_SIZE = 3;
38	const BLOCK_PREMIUM = 60;
39	
40	const formsBlock = (type: string, count: number): boolean =>
41	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
42	
43	const typeBasePremium = (type: string, count: number): number => {
44	  if (formsBlock(type, count)) return BLOCK_PREMIUM;
45	  return count * BASE_PREMIUMS[type];
46	};
47	
48	const policyBasePremium = (items: Item[]): number => {
49	  const counts = new Map<string, number>();
50	  for (const item of items) {
51	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
52	  }
53	  return [...counts].reduce(
54	    (base, [type, count]) => base + typeBasePremium(type, count),
55	    0,
56	  );
57	};
58	
59	const CURSE_SURCHARGE = 0.5;
60	
61	const itemSurcharges = (items: Item[]): number =>
62	  items.reduce(
63	    (sum, item) => sum + (item.cursed ? CURSE_SURCHARGE * BASE_PREMIUMS[item.type] : 0),
64	    0,
65	  );
66	
67	// Premiums round up (in the MHPCO's favor); toFixed guards against
68	// floating-point error nudging an exact value over an integer boundary.
69	const roundUpPremium = (amount: number): number =>
70	  Math.ceil(Number(amount.toFixed(6)));
71	
72	const quotePremium = (step: QuoteStep): number => {
73	  const base = policyBasePremium(step.items);
74	  const total =
75	    base + itemSurcharges(step.items) + base * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
76	  return roundUpPremium(total);
77	};
78	
79	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
80	  return { results: scenario.steps.map((step) => ({ premium: quotePremium(step) })) };
81	};
